// This workflow is an ALTERNATIVE to the built-in /api/webhook route.
// Use this if you want N8N to handle all Meta webhook events instead of Next.js.
// 
// The preferred approach is to use the Next.js /api/webhook route directly,
// which handles both incoming messages and delivery status updates.
//
// If you use this workflow:
// 1. Point your Meta App webhook to this N8N webhook URL instead
// 2. Disable the GET verification in this workflow (Meta handles that via your Next.js route)

const body = $input.first().json.body;

if (body.object !== 'whatsapp_business_account') {
  return [{ json: { status: 'ignored' } }];
}

const statusUpdates = [];
const incomingMessages = [];

for (const entry of body.entry || []) {
  for (const change of entry.changes || []) {
    const value = change.value;

    if (value.statuses) {
      for (const status of value.statuses) {
        statusUpdates.push({
          wamid: status.id,
          status: status.status,
          timestamp: status.timestamp
        });
      }
    }

    if (value.messages) {
      for (const msg of value.messages) {
        incomingMessages.push({
          from: msg.from,
          text: msg.text?.body || '[media]',
          wamid: msg.id,
          timestamp: msg.timestamp,
          contact_name: value.contacts?.find(c => c.wa_id === msg.from)?.profile?.name || null
        });
      }
    }
  }
}

return [{ json: { statusUpdates, incomingMessages } }];
